import React, { useState, useEffect, useMemo, useRef, useLayoutEffect } from "react";
import { Link } from "react-router-dom";
import {
  Grid,
  Typography,
  Box,
  TextField,
  Alert,
  Card,
  CardMedia,
  CardContent,
  Button,
  InputAdornment,
  Chip,
  IconButton,
} from "@mui/material";

import SearchIcon from "@mui/icons-material/Search";
import PushPinIcon from "@mui/icons-material/PushPin";
import PushPinOutlinedIcon from "@mui/icons-material/PushPinOutlined";

import LockOutlinedIcon from "@mui/icons-material/LockOutlined";
import VerifiedUserOutlinedIcon from "@mui/icons-material/VerifiedUserOutlined";
import BoltOutlinedIcon from "@mui/icons-material/BoltOutlined";
import SupportAgentOutlinedIcon from "@mui/icons-material/SupportAgentOutlined";

import { motion } from "framer-motion";
import UserGuard from "../../../../utils/UserGuard";
import { mobileNumberFilter } from "../../../../baseUrl";
import { bankbg4 } from "../../../../asesets";

const categories = ["ALL", "DMT", "AEPS", "Bill Payments & Recharge", "Travel"];

const BBPS_TRAVEL_SERVICES = [
  "Hotel",
  "Bus",
  "Fastag",
  "Metro Recharge",
  "NCMC Recharge",
  "IRCTC",
];

const getBbpsSubCategory = (serviceName) =>
  BBPS_TRAVEL_SERVICES.includes(serviceName) ? "Travel" : "Bill Payments & Recharge";

const getDisplayCategory = (service) =>
  service?.service_category === "BBPS"
    ? getBbpsSubCategory(service?.service_name)
    : service?.service_category;

const MAX_PINNED = 6;
const MAX_RECENT = 6;
const MAX_MOST_USED = 6;

const LS_KEYS = {
  PINNED: "bm_pinned_services",
  RECENT: "bm_recent_services",
  MOST_USED: "bm_most_used_services",
};

const SERVICE_FEATURES = {
  DMT: "Fast • Secure • RBI",
  AEPS: "Biometric • NPCI • Aadhaar",
  BBPS: "Utility • Bharat BillPay",
};

const COMPLIANCE = {
  DMT: "Encrypted • RBI",
  AEPS: "Encrypted • NPCI",
  BBPS: "Encrypted • BBPS",
};

const getTimeSlot = () => {
  const hour = new Date().getHours();
  if (hour >= 5 && hour < 12) return "morning";
  if (hour >= 12 && hour < 17) return "afternoon";
  if (hour >= 17 && hour < 21) return "evening";
  return "night";
};

const TIME_BASED_GREETINGS = {
  morning: [
    { title: "Good Morning", sub: "Start your day with secure digital payments" },
    { title: "Morning!", sub: "Check balances, settlements & payouts" },
    { title: "Ready for Business", sub: "All banking services are live and secure" },
  ],
  afternoon: [
    { title: "Good Afternoon", sub: "Fast, compliant & real-time transactions" },
    { title: "Midday Status", sub: "Monitor transfers and AEPS activity" },
    { title: "Business in Motion", sub: "Payments running smoothly across services" },
  ],
  evening: [
    { title: "Good Evening", sub: "Review today's transactions & settlements" },
    { title: "End-of-Day Check", sub: "Track earnings and service performance" },
    { title: "Stay in Control", sub: "Smart finance for a productive tomorrow" },
  ],
  night: [
    { title: "Good Night", sub: "Your money is protected with bank-grade security" },
    { title: "Always On", sub: "24×7 fintech services, even after hours" },
    { title: "System Active", sub: "Transactions will continue uninterrupted" },
  ],
};

const ROLE_SUBTEXT = {
  Admin: "Monitor platform health & settlements",
  Distributor: "Track commissions & agent activity",
  Retailer: "Process transactions faster today",
  User: "Quick access to daily services",
};

const TRUST_BADGES = [
  { icon: LockOutlinedIcon, title: "Secure Transactions", sub: "Bank-level security" },
  { icon: VerifiedUserOutlinedIcon, title: "RBI Compliant", sub: "100% Secure & Trusted" },
  { icon: BoltOutlinedIcon, title: "Instant & Reliable", sub: "Fast • Easy • Dependable" },
  { icon: SupportAgentOutlinedIcon, title: "24/7 Support", sub: "We're here to help" },
];

const getLS = (key, fallback = []) =>
  JSON.parse(localStorage.getItem(key)) || fallback;

const setLS = (key, value) => localStorage.setItem(key, JSON.stringify(value));

const BADGE_COLORS = {
  "MOST USED": { bg: "#1565c0", color: "#ffffff" },
  FAST: { bg: "#1565c0", color: "#ffffff" },
  RECOMMENDED: { bg: "#2e7d32", color: "#ffffff" },
  PINNED: { bg: "#6a1b9a", color: "#ffffff" },
  RECENT: { bg: "#2e7d32", color: "#ffffff" },
};

const PAGE_PADDING = { xs: 1, sm: 1.5, md: 2 };

const ServiceCard = ({ service, pinned, onPin, onClick, badge }) => {
  const serviceName = service?.service_name || "Unnamed Service";
  const serviceIcon = service?.icon || "/servicesicon.png";
  const pathName = service?.route || "#";

  return (
    <Grid item xs={6} sm={4} md={2.4} lg={2.4}>
      <Link to={pathName} onClick={onClick} style={{ textDecoration: "none" }}>
        <motion.div whileHover={{ y: -4 }} transition={{ duration: 0.2 }}>
          <Card
            className="boxModel"
            sx={{
                maxWidth: 240,
    mx: "auto",
              height: "100%",
              minHeight: 138,
              borderRadius: "18px",
              padding: "16px",
              position: "relative",
              overflow: "hidden",
              display: "flex",
              flexDirection: "column",
              gap: 1,
              backgroundColor: "#ffffff",
              border: "1px solid #edf0f5",
              boxShadow: "0 2px 8px rgba(16,24,40,0.06)",
              transition: "box-shadow 0.25s ease, border-color 0.25s ease, transform 0.2s ease",
              "&::before": {
                content: '""',
                position: "absolute",
                inset: 0,
                backgroundImage: `url(${serviceIcon})`,
                backgroundRepeat: "no-repeat",
                backgroundPosition: "center",
                backgroundSize: "120px",
                opacity: 0.05,
                filter: "grayscale(100%)",
                transition: "all 0.45s ease",
                zIndex: 0,
              },
              "&::after": {
                content: '""',
                position: "absolute",
                inset: 0,
                background:
                  "linear-gradient(120deg, transparent 30%, rgba(255,255,255,0.8), transparent 70%)",
                opacity: 0,
                transform: "translateX(-100%)",
                transition: "all 0.6s ease",
                zIndex: 1,
              },
              "&:hover": {
                borderColor: "#c9d6e8",
                boxShadow: "0 12px 28px rgba(21,101,192,0.16)",
                "&::before": { opacity: 0.1, transform: "scale(1.15) rotate(8deg)" },
                "&::after": { opacity: 1, transform: "translateX(100%)" },
                "& .service-icon-img": { transform: "scale(1.1)" },
              },
            }}
          >
            {/* Row 1: icon (left) + badge (right) — title is NOT in this row, so it can never be covered */}
            <Box
              sx={{
                display: "flex",
                alignItems: "flex-start",
                justifyContent: "space-between",
                position: "relative",
                zIndex: 2,
              }}
            >
              <Box
                sx={{
                  flexShrink: 0,
                  width: 66,
                  height: 66,
                  borderRadius: "16px",
                  background: "linear-gradient(135deg, #eaf1fb 0%, #d8e6fb 100%)",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                }}
              >
                <CardMedia
                  component="img"
                  className="service-icon-img"
                  src={serviceIcon}
                  alt={serviceName}
                  loading="eager"
                  onError={(e) => {
                    e.target.onerror = null;
                    e.target.src = "/servicesicon.png";
                  }}
                  sx={{
                    width: 38,
                    height: 38,
                    objectFit: "contain",
                    transition: "transform 0.3s ease",
                  }}
                />
              </Box>

              {badge && (
                <Chip
                  label={badge}
                  size="small"
                  sx={{
                    bgcolor: BADGE_COLORS[badge]?.bg || "#eee",
                    color: BADGE_COLORS[badge]?.color || "#333",
                    fontSize: 10,
                    fontWeight: 700,
                    letterSpacing: 0.3,
                    height: 22,
                    borderRadius: "6px",
                  }}
                />
              )}
            </Box>

            {/* Row 2: title + meta — full width, guaranteed clear of the badge */}
            <CardContent
              sx={{
                padding: "0 !important",
                pr: 4,
                flex: 1,
                minWidth: 0,
                position: "relative",
                zIndex: 2,
              }}
            >
              <Typography
                className="service-title"
                variant="body2"
                sx={{
                  fontSize: "15.5px",
                  fontWeight: 700,
                  lineHeight: 1.3,
                  color: "#1f2933",
                  mb: 0.4,
                  display: "-webkit-box",
                  WebkitLineClamp: 2,
                  WebkitBoxOrient: "vertical",
                  overflow: "hidden",
                  textOverflow: "ellipsis",
                }}
              >
                {serviceName}
              </Typography>

              {SERVICE_FEATURES?.[service?.service_category] && (
                <Typography sx={{ fontSize: "11.5px", fontWeight: 500, color: "#8a94a0", mb: 0.4 }}>
                  {SERVICE_FEATURES[service.service_category]}
                </Typography>
              )}

              {COMPLIANCE?.[service?.service_category] && (
                <Typography sx={{ fontSize: "11px", fontWeight: 600, color: "#2e7d32", lineHeight: 1.3 }}>
                  {COMPLIANCE[service.service_category]}
                </Typography>
              )}
            </CardContent>

            <IconButton
              onClick={(e) => {
                e.preventDefault();
                e.stopPropagation();
                onPin();
              }}
              size="small"
              sx={{
                position: "absolute",
                bottom: 10,
                right: 10,
                zIndex: 3,
                padding: "4px",
                "&:hover": { bgcolor: "#f5f6f7" },
              }}
            >
              {pinned ? (
                <PushPinIcon sx={{ fontSize: 16, color: "#6a1b9a" }} />
              ) : (
                <PushPinOutlinedIcon sx={{ fontSize: 16, color: "#c7cdd4" }} />
              )}
            </IconButton>
          </Card>
        </motion.div>
      </Link>
    </Grid>
  );
};

function ServiceGrid({ services = [] }) {
  const userNumber = localStorage.getItem("regisNumber");
  const storedUserType = localStorage.getItem("userType");

  const [searchTerm, setSearchTerm] = useState("");
  const [activeCategory, setActiveCategory] = useState("ALL");

  const [pinned, setPinned] = useState([]);
  const [recent, setRecent] = useState([]);
  const [mostUsed, setMostUsed] = useState([]);

  const [searchHintIndex, setSearchHintIndex] = useState(0);
  const [greetingIndex, setGreetingIndex] = useState(0);

  const bleedRef = useRef(null);
  const [bleed, setBleed] = useState({ left: 0, right: 0 });

  useLayoutEffect(() => {
    const measure = () => {
      if (!bleedRef.current) return;
      const rect = bleedRef.current.getBoundingClientRect();
      setBleed({
        left: rect.left,
        right: window.innerWidth - rect.right,
      });
    };

    measure();
    window.addEventListener("resize", measure);

    const ro = new ResizeObserver(measure);
    if (bleedRef.current) ro.observe(bleedRef.current);

    return () => {
      window.removeEventListener("resize", measure);
      ro.disconnect();
    };
  }, []);

  const SEARCH_HINTS = useMemo(() => {
    if (!services?.length) return [];
    const hints = new Set();
    services.forEach((s) => {
      if (!s?.service_name) return;
      hints.add(s.service_name);
      if (s.service_name.includes("Transfer")) {
        hints.add("Bank Transfer");
        hints.add("Money Transfer");
      }
      if (s.service_name.includes("Recharge")) {
        hints.add("Mobile Recharge");
        hints.add("Recharge");
      }
      if (s.service_name.includes("Electricity")) {
        hints.add("Electricity Bill");
      }
      if (s.service_name.includes("Aadhaar")) {
        hints.add("AEPS Aadhaar");
        hints.add("Aadhaar Services");
      }
      if (s.service_name.includes("Gas")) {
        hints.add("Gas Bill");
      }
      if (s.service_name.includes("Insurance")) {
        hints.add("Insurance Payment");
      }
    });
    return Array.from(hints);
  }, [services]);

  useEffect(() => {
    setPinned(getLS(LS_KEYS.PINNED));
    setRecent(getLS(LS_KEYS.RECENT));
    setMostUsed(getLS(LS_KEYS.MOST_USED));
  }, []);

  useEffect(() => {
    if (!SEARCH_HINTS.length) return;
    const interval = setInterval(() => {
      setSearchHintIndex((p) => (p + 1) % SEARCH_HINTS.length);
    }, 3000);
    return () => clearInterval(interval);
  }, [SEARCH_HINTS]);

  const timeSlot = getTimeSlot();
  const greetings = TIME_BASED_GREETINGS[timeSlot];

  useEffect(() => {
    const interval = setInterval(() => {
      setGreetingIndex((prev) => (prev + 1) % greetings.length);
    }, 5000);
    return () => clearInterval(interval);
  }, [timeSlot]);

  const handlePin = (service) => {
    const updated = pinned.some((s) => s._id === service._id)
      ? pinned.filter((s) => s._id !== service._id)
      : [service, ...pinned].slice(0, MAX_PINNED);

    setPinned(updated);
    setLS(LS_KEYS.PINNED, updated);
  };

  const handleClick = (service) => {
    const r = [service, ...recent.filter((s) => s._id !== service._id)].slice(0, MAX_RECENT);
    setRecent(r);
    setLS(LS_KEYS.RECENT, r);

    const usage = getLS(LS_KEYS.MOST_USED, {});
    usage[service._id] = (usage[service._id] || 0) + 1;
    setLS(LS_KEYS.MOST_USED, usage);

    const sorted = Object.entries(usage)
      .sort((a, b) => b[1] - a[1])
      .map(([id]) => services.find((s) => s._id === id))
      .filter(Boolean)
      .slice(0, MAX_MOST_USED);

    setMostUsed(sorted);
  };

  const filtered = useMemo(() => {
    return services.filter((s) => {
      const matchesSearch = s.service_name?.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesCategory =
        activeCategory === "ALL"
          ? true
          : activeCategory === "Bill Payments & Recharge" || activeCategory === "Travel"
          ? s.service_category === "BBPS" && getBbpsSubCategory(s.service_name) === activeCategory
          : s.service_category === activeCategory;

      return matchesSearch && matchesCategory;
    });
  }, [services, searchTerm, activeCategory]);

  const grouped = useMemo(() => {
    return filtered.reduce((acc, s) => {
      const cat = getDisplayCategory(s);
      acc[cat] = acc[cat] || [];
      acc[cat].push(s);
      return acc;
    }, {});
  }, [filtered]);

  return (
    <Box
      ref={bleedRef}
      sx={{
        py: 2,
        position: "relative",
        minHeight: "100vh",
        width: "100%",
      }}
    >
      <Box
        sx={{
          position: "fixed",
          top: 0,
          left: 0,
          width: "100vw",
          height: "100vh",
          zIndex: 0,
          backgroundImage: `linear-gradient(180deg, rgba(255,255,255,0.42) 0%, rgba(255,255,255,0.5) 100%), url(${bankbg4})`,
          backgroundSize: "cover",
          backgroundPosition: "top center",
          backgroundRepeat: "no-repeat",
          pointerEvents: "none",
        }}
      />

      <Box sx={{ position: "relative", zIndex: 1 }}>

        <Box sx={{ position: "relative", mb: 4, px: PAGE_PADDING, pt: 3 }}>
          <UserGuard
            currentUser={storedUserType}
            excludeUserList={["Reseller", "reseller partner api user"]}
          >
            {mobileNumberFilter?.includes(userNumber) !== true && (
              <Box sx={{ textAlign: { xs: "left", sm: "center" }, mb: 3 }}>
                <Typography
                  variant="h3"
                  fontWeight={800}
                  sx={{
                    color: "#16305c",
                    fontSize: { xs: "26px", sm: "34px", md: "40px" },
                    lineHeight: 1.2,
                    textShadow: "0 2px 12px rgba(255,255,255,0.6)",
                  }}
                >
                  {greetings[greetingIndex].title}
                </Typography>
                <Typography
                  sx={{
                    mt: 0.75,
                    color: "#3f5a7d",
                    fontSize: { xs: 14, sm: 16 },
                    textShadow: "0 1px 8px rgba(255,255,255,0.6)",
                  }}
                >
                  {ROLE_SUBTEXT[storedUserType] || greetings[greetingIndex].sub}
                </Typography>
              </Box>
            )}
          </UserGuard>

          <Box sx={{ display: "flex", justifyContent: { xs: "flex-start", sm: "center" } }}>
           <TextField
  fullWidth
  placeholder={`Search ${SEARCH_HINTS[searchHintIndex] || ""}...`}
  value={searchTerm}
  onChange={(e) => setSearchTerm(e.target.value)}
  InputProps={{
    startAdornment: (
      <InputAdornment position="start">
        <SearchIcon sx={{ color: "#8a94a0" }} />
      </InputAdornment>
    ),
  }}
  sx={{
    maxWidth: 480,
    "& .MuiOutlinedInput-root": {
      borderRadius: "999px",
      height: 52,
      px: 1,
      bgcolor: "rgba(255,255,255,0.95)",
      boxShadow: "0 4px 18px rgba(16,24,40,0.12)",
      overflow: "hidden",
      "& .MuiOutlinedInput-notchedOutline": {
        borderRadius: "999px",
        border: "1px solid rgba(200,210,225,0.7)",
      },
    },
    "& input": { color: "#1f2933", fontSize: "14.5px" },
    "& input::placeholder": { color: "#9aa0a6", opacity: 1 },
  }}
/>
          </Box>
        </Box>

        <Box sx={{ display: "flex", gap: 1.5, mb: 4, flexWrap: "wrap", px: PAGE_PADDING }}>
          {categories.map((c) => (
            <Button
              key={c}
              variant={activeCategory === c ? "contained" : "outlined"}
              onClick={() => setActiveCategory(c)}
              sx={{
                px: 3,
                py: 1,
                borderRadius: "10px",
                fontWeight: 600,
                textTransform: "none",
                backgroundColor: activeCategory === c ? "#1565c0" : "rgba(255,255,255,0.9)",
                color: activeCategory === c ? "#ffffff" : "#1f2933",
                border: activeCategory === c ? "none" : "1px solid #dfe3e8",
                "&:hover": {
                  backgroundColor: activeCategory === c ? "#0d47a1" : "#f5f6f7",
                  borderColor: "#c1c7cd",
                },
              }}
            >
              {c}
            </Button>
          ))}
        </Box>

        {pinned.length > 0 && (
          <Box mb={5} px={PAGE_PADDING}>
            <Typography fontWeight={800} mb={2} sx={{ color: "#1f2933", letterSpacing: 0.3 }}>
              PINNED
            </Typography>
            <Grid
              container
              spacing={2.5}
              sx={{
                m: 0,
                width: "100%",
              }}
            >
              {pinned.map((s) => (
                <ServiceCard
                  key={s._id}
                  service={s}
                  pinned
                  badge="PINNED"
                  onPin={() => handlePin(s)}
                  onClick={() => handleClick(s)}
                />
              ))}
            </Grid>
          </Box>
        )}

        {mostUsed.length > 0 && (
          <Box
            mb={5}
            sx={{
              px: PAGE_PADDING,
              overflow: "hidden",
            }}
          >
            <Typography fontWeight={800} mb={2} sx={{ color: "#1f2933", letterSpacing: 0.3 }}>
              MOST USED
            </Typography>
            <Grid container spacing={2.5}>
              {mostUsed.map((s) => (
                <ServiceCard
                  key={s._id}
                  service={s}
                  pinned={pinned.some((p) => p._id === s._id)}
                  badge="MOST USED"
                  onPin={() => handlePin(s)}
                  onClick={() => handleClick(s)}
                />
              ))}
            </Grid>
          </Box>
        )}

        {Object.entries(grouped).map(([cat, list]) => (
          <Box key={cat} mb={5} px={PAGE_PADDING}>
            <Typography fontWeight={800} mb={2} sx={{ color: "#1f2933", letterSpacing: 0.3 }}>
              {cat}
            </Typography>
            <Grid container spacing={2.5}>
              {list.map((s) => (
                <ServiceCard
                  key={s._id}
                  service={s}
                  pinned={pinned.some((p) => p._id === s._id)}
                  badge={
                    [
                      "B2B UPI",
                      "B2B Bank Transfer",
                      "Bank Transfer",
                      "PPI Bank Transfer",
                      "Electricity",
                      "Electricity (Prepaid)",
                      "Mobile Recharge",
                      "Fastag",
                      "Credit Card",
                    ].includes(s?.service_name)
                      ? "MOST USED"
                      : [
                            "AFT",
                            "B2B UPI",
                            "Metro Recharge",
                            "NCMC Recharge",
                            "DTH",
                            "Mobile Postpaid",
                            "IRCTC",
                          ].includes(s?.service_name)
                        ? "FAST"
                        : ["AEPS"].includes(s?.service_category)
                          ? "MOST USED"
                          : null
                  }
                  onPin={() => handlePin(s)}
                  onClick={() => handleClick(s)}
                />
              ))}
            </Grid>
          </Box>
        ))}

        {recent.length > 0 && (
          <Box mb={5} px={PAGE_PADDING}>
            <Typography fontWeight={800} mb={2} sx={{ color: "#1f2933", letterSpacing: 0.3 }}>
              RECENTLY USED
            </Typography>
            <Grid container spacing={2.5}>
              {recent.map((s) => (
                <ServiceCard
                  key={s._id}
                  service={s}
                  pinned={pinned.some((p) => p._id === s._id)}
                  badge="RECENT"
                  onPin={() => handlePin(s)}
                  onClick={() => handleClick(s)}
                />
              ))}
            </Grid>
          </Box>
        )}

        {filtered.length === 0 && (
          <Box px={PAGE_PADDING}>
            <Alert severity="info">No services found</Alert>
          </Box>
        )}

        <Box
          sx={{
            mt: 5,
            mx: PAGE_PADDING,
            p: { xs: 2.5, sm: 3 },
            borderRadius: 3,
            bgcolor: "rgba(238,244,252,0.92)",
          }}
        >
          <Grid container spacing={2}>
            {TRUST_BADGES.map(({ icon: Icon, title, sub }) => (
              <Grid item xs={6} sm={3} key={title}>
                <Box sx={{ display: "flex", alignItems: "center", gap: 1.25 }}>
                  <Box
                    sx={{
                      flexShrink: 0,
                      width: 40,
                      height: 40,
                      borderRadius: "50%",
                      bgcolor: "#ffffff",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                    }}
                  >
                    <Icon sx={{ fontSize: 20, color: "#1565c0" }} />
                  </Box>
                  <Box sx={{ minWidth: 0 }}>
                    <Typography sx={{ fontSize: 13, fontWeight: 700, color: "#1f2933", lineHeight: 1.3 }}>
                      {title}
                    </Typography>
                    <Typography sx={{ fontSize: 11, color: "#5f6b76", lineHeight: 1.3 }}>
                      {sub}
                    </Typography>
                  </Box>
                </Box>
              </Grid>
            ))}
          </Grid>
        </Box>
      </Box>
    </Box>
  );
}

export default ServiceGrid;